                        placeholder="اطلب تعديلاً..."
                        className="flex-1 bg-transparent focus:outline-none px-2 text-white text-sm"
                        disabled={isChatLoading}
                    />
                    <button onClick={handleChatSend} disabled={(!input.trim() && chatImages.length === 0) || isChatLoading} className="bg-indigo-600 text-white rounded-md p-2 disabled:bg-slate-500">
                        {isChatLoading ? <SpinnerIcon className="w-5 h-5 animate-spin"/> : <SendIcon className="w-5 h-5" />}
                    </button>
                </div>
                 <div className="h-20 overflow-y-auto text-sm pr-2 space-y-2 mt-2">
                    {messages.map(msg => (
                        <div key={msg.id}>
                            <p className={`${msg.sender === 'user' ? 'text-indigo-300' : 'text-slate-300'}`}>
                                <strong>{msg.sender === 'user' ? 'أنت' : 'AI'}:</strong> {msg.text}
                            </p>
                            {msg.attachments && msg.attachments.length > 0 && (
                                <div className="mt-1 flex gap-1 flex-wrap">
                                    {msg.attachments.map((att, i) => (
                                        <img key={i} src={att.url} alt={att.name} className="w-10 h-10 object-cover rounded" />
                                    ))}
                                </div>
                            )}
                        </div>
                    ))}
                    <div ref={messagesEndRef} />
                </div>
            </div>
        </div>
    );

    if (isGenerating) return <LoadingScreen logs={logs} projectType={projectType}/>;

    switch(screen) {
        case 'list': return renderListView();
        case 'generator': return renderGeneratorView();
        case 'editor': return project ? (
            <>
                {renderEditorView()}
                <BuildModal isOpen={isBuildModalOpen} onClose={() => setIsBuildModalOpen(false)} project={project} platform={buildPlatform} />
                <QualityAnalysisModal isOpen={isAnalysisModalOpen} onClose={() => setIsAnalysisModalOpen(false)} project={project}/>
            </>
        ) : renderListView(); // Fallback if project is somehow null
        default: return renderListView();
    }
};

