```typescript
import { GoogleGenAI, GenerateContentResponse, Type, Modality, FunctionDeclaration } from '@google/genai';
import { Project, ProjectFile, ProjectSection, ProjectType, DesignConfig, MarketingSuggestion, MarketingAsset, Message, SectionType, User, ProjectIdea } from '../types';
import { SECTION_DEFINITIONS, getInitialSectionsForProjectType, PLAN_SECTIONS } from '../constants';

// --- Gemini API Initialization ---
// The API key is sourced from process.env.API_KEY as per the guidelines.
const getClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });


// A helper function to simulate network delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

class GeminiService {

    // --- Core Generation Methods ---

    async generateContent(prompt: string, model: string = 'gemini-2.5-flash', config?: any): Promise<GenerateContentResponse> {
        try {
            const ai = getClient();
            const response: GenerateContentResponse = await ai.models.generateContent({
                model,
                contents: prompt,
                config,
            });
            return response;
        } catch (e) {
            console.error(`[GeminiService] Error in generateContent for model ${model}:`, e);
            throw e;
        }
    }

    async generateText(prompt: string, model: string = 'gemini-2.5-flash', config?: any): Promise<string> {
        try {
            const ai = getClient();
            const response: GenerateContentResponse = await ai.models.generateContent({
                model,
                contents: prompt,
                config,
            });
            return response.text;
        } catch (e) {
            console.error(`[GeminiService] Error in generateText for model ${model}:`, e);
            throw e;
        }
    }

    async generateTextStream({ prompt, model, systemInstruction, config, onChunk, onComplete }: {
        prompt: string;
        model: string;
        systemInstruction?: string;
        config?: any;
        onChunk: (chunk: string) => void;
        onComplete: () => void;
    }) {
        try {
            const ai = getClient();
            const response = await ai.models.generateContentStream({
                model,
                contents: prompt,
                config: {
                    ...config,
                    ...(systemInstruction && { systemInstruction }),
                },
            });

            for await (const chunk of response) {
                onChunk(chunk.text);
            }
        } catch (e) {
            console.error(`[GeminiService] Error in generateTextStream for model ${model}:`, e);
            onChunk(`\n\n**ERROR**: ${e instanceof Error ? e.message : 'An unknown error occurred.'}`);
        } finally {
            onComplete();
        }
    }

