                             <button onClick={handleGenerateIcon} disabled={isGeneratingIcon} className="self-end p-2 bg-indigo-600 hover:bg-indigo-500 rounded-lg disabled:bg-slate-500" title="إنشاء أيقونة بالذكاء الاصطناعي">
