// --- START: Blob URL Resolver ---
export const resolveBlobUrlToDataUrl = async (url: string): Promise<string> => {
    if (!url || !url.startsWith('blob:')) {
      return url;
    }

    try {
      const response = await fetch(url);
      if (!response.ok) {
          throw new Error(`Network response was not ok, status: ${response.status}`);
      }
      const blob = await response.blob();

      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          if (typeof reader.result === 'string') {
               resolve(reader.result);
          } else {
               reject(new Error('FileReader did not return a string.'));
          }
        };
        reader.onerror = reject;
        reader.readAsDataURL(blob);
      });
    } catch (error) {
      console.error('Failed to resolve blob URL:', error);
      return url; // Fallback to the original URL on error
    }
  };
// --- END: Blob URL Resolver ---

// --- START: Safe LocalStorage Helpers ---
const safeGetItem = (key: string): string | null => {
    try {
        return localStorage.getItem(key);
    } catch (e) {
        console.warn(`Failed to get item "${key}" from localStorage:`, e);
        return null;
    }
};

const safeSetItem = (key: string, value: string): void => {
    try {
        localStorage.setItem(key, value);
    } catch (e) {
        console.warn(`Failed to set item "${key}" in localStorage:`, e);
    }
};

const safeRemoveItem = (key: string): void => {
    try {
        localStorage.removeItem(key);
    } catch (e) {
        console.warn(`Failed to remove item "${key}" from localStorage:`, e);
    }
};

const safeJsonParse = <T,>(jsonString: string | null, fallback: T): T => {
    if (jsonString === null) {
        return fallback;
    }
    try {
        return JSON.parse(jsonString) as T;
    } catch (e) {
        console.warn(`Failed to parse JSON from localStorage:`, e);
        return fallback;
    }
};
// --- END: Safe LocalStorage Helpers ---

// --- START: Payment Service Implementation ---
export interface SubscriptionRecord {
    subscriptionId: string;
    userId: string;
    planId: PlanId;
    walletAddress: string;
    txHash: string | null;
    chainId: string | null;
    amount: number;
    currency: string;
    confirmations: number;
    status: 'pending' | 'confirmed' | 'failed' | 'error';
    createdAt: string;
}

interface AuditEvent {
    ts: string;
    eventType: string;
    details: any;
}

const LEDGER_KEY = 'paymentLedger';
const AUDIT_KEY = 'paymentAuditLog';

const getLedger = (): Record<string, SubscriptionRecord> => {
    return safeJsonParse<Record<string, SubscriptionRecord>>(safeGetItem(LEDGER_KEY), {});
};
const saveLedger = (ledger: Record<string, SubscriptionRecord>) => {
    safeSetItem(LEDGER_KEY, JSON.stringify(ledger));
};

const getAuditLog = (): Record<string, AuditEvent[]> => {
    return safeJsonParse<Record<string, AuditEvent[]>>(safeGetItem(AUDIT_KEY), {});
};
const saveAuditLog = (log: Record<string, AuditEvent[]>) => {
    safeSetItem(AUDIT_KEY, JSON.stringify(log));
};

const logEvent = (subscriptionId: string, eventType: string, details: any) => {
    const auditLog = getAuditLog();
    if (!auditLog[subscriptionId]) {
        auditLog[subscriptionId] = [];
    }
    auditLog[subscriptionId].push({ ts: new Date().toISOString(), eventType, details });
    saveAuditLog(auditLog);
};

const recordPaymentAttempt = async (
    userId: string,
    planId: PlanId,
    walletAddress: string,
    amount: number,
    currency: string
): Promise<SubscriptionRecord> => {
    const subscriptionId = `sub_${Date.now()}`;
    const record: SubscriptionRecord = {
        subscriptionId,
        userId,
        planId,
        walletAddress,
        txHash: null,
        chainId: null,
        amount,
        currency,
        confirmations: 0,
        status: 'pending',
        createdAt: new Date().toISOString(),
    };

    const ledger = getLedger();
    ledger[subscriptionId] = record;
    saveLedger(ledger);
    logEvent(subscriptionId, 'attempt_created', { planId, amount, currency });

    return record;
};

const verifyTransactionOnChain = async (
    txHash: string
): Promise<{ status: 'pending' | 'confirmed' | 'failed' | 'not_found'; confirmations: number }> => {
    await new Promise(res => setTimeout(res, 3000)); // Simulate network latency
    const trimmedHash = txHash.trim().toLowerCase();
    if (!trimmedHash || trimmedHash.length < 10) return { status: 'not_found', confirmations: 0 };
    if (trimmedHash.includes('fail')) return { status: 'failed', confirmations: 1 };
    if (trimmedHash.includes('pending')) return { status: 'pending', confirmations: 2 }; 
    if (trimmedHash.includes('valid')) return { status: 'confirmed', confirmations: 12 };
    if (trimmedHash.startsWith('0x') && trimmedHash.length > 60) return { status: 'confirmed', confirmations: 15 };
    return { status: 'not_found', confirmations: 0 };
};

const handlePaymentVerification = async (
    subscriptionId: string,
    txHash: string
): Promise<SubscriptionRecord> => {
    const ledger = getLedger();
    const record = ledger[subscriptionId];
    if (!record) {
        logEvent(subscriptionId, 'verification_error', { error: 'Subscription record not found.' });
        throw new Error('Subscription record not found.');
    }
    logEvent(subscriptionId, 'verification_started', { txHash });
    record.txHash = txHash;
    const verification = await verifyTransactionOnChain(txHash);
    record.confirmations = verification.confirmations;
    switch (verification.status) {
        case 'confirmed':
            record.status = 'confirmed';
            logEvent(subscriptionId, 'verification_success', { confirmations: verification.confirmations });
            break;
        case 'pending':
            record.status = 'pending';
            logEvent(subscriptionId, 'verification_pending', { confirmations: verification.confirmations });
            break;
        case 'failed':
            record.status = 'failed';
            logEvent(subscriptionId, 'verification_failed', { reason: 'Transaction failed on-chain' });
            break;
        case 'not_found':
            record.status = 'failed';
            logEvent(subscriptionId, 'verification_failed', { reason: 'Transaction not found' });
            break;
        default:
             record.status = 'error';
             logEvent(subscriptionId, 'verification_error', { reason: 'Unknown verification status' });
    }
    ledger[subscriptionId] = record;
    saveLedger(ledger);
    return record;
};

export const paymentService = {
    recordPaymentAttempt,
    handlePaymentVerification,
};
// --- END: Payment Service Implementation ---

export const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  useEffect(() => {
    const storedUser = safeGetItem('currentUser');
    if (storedUser) {
      const parsedUser = safeJsonParse<User | null>(storedUser, null);
      if (parsedUser) {
          if (typeof parsedUser.points === 'undefined') parsedUser.points = 0;
          if (typeof parsedUser.freeMarketingContentUsed === 'undefined') parsedUser.freeMarketingContentUsed = 0;
          if (typeof parsedUser.warnings === 'undefined') parsedUser.warnings = 0;
          if (typeof parsedUser.isBanned === 'undefined') parsedUser.isBanned = false;
          if (typeof parsedUser.isNewUser === 'undefined') parsedUser.isNewUser = false;
          setCurrentUser(parsedUser);
      }
    }
  }, []);

  const logout = () => {
    safeRemoveItem('currentUser');
    setCurrentUser(null);
  };

  const updateUser = async (updates: Partial<User>) => {
    if (!currentUser) return;
    const updatedUser = { ...currentUser, ...updates };
    setCurrentUser(updatedUser);
    safeSetItem('currentUser', JSON.stringify(updatedUser));
    let users = safeJsonParse<(User & {pass: string})[]>(safeGetItem('users'), []);
    const userIndex = users.findIndex((u: User) => u.email === currentUser.email);
    if (userIndex > -1) {
      const oldUserRecord = users[userIndex];
      users[userIndex] = { ...oldUserRecord, ...updatedUser };
      safeSetItem('users', JSON.stringify(users));
    }
  };

  const upgradePlan = async (plan: PlanId) => {
    if (!currentUser) return;
    const updatedUser = { ...currentUser, plan };
    setCurrentUser(updatedUser);
    safeSetItem('currentUser', JSON.stringify(updatedUser));
    let users: (User & { pass: string })[] = safeJsonParse(safeGetItem('users'), []);
    const userIndex = users.findIndex((u: User) => u.email === currentUser.email);
    if (userIndex > -1) {
        users[userIndex].plan = plan;
        safeSetItem('users', JSON.stringify(users));
    }
  };

  const redeemPointsForPlan = async (plan: PlanId, pointsCost: number): Promise<boolean> => {
    if (!currentUser || (currentUser.points || 0) < pointsCost) return false;
    try {
        await updateUser({ points: (currentUser.points || 0) - pointsCost, plan: plan });
        return true;
    } catch (error) {
        console.error("Redemption failed:", error);
        return false;
    }
  };

  const reportProject = async (reportedProject: Project, reason: string): Promise<{ success: boolean, message: string }> => {
    if (!currentUser) return { success: false, message: "You must be logged in to report."};
    if (!reason) return { success: false, message: "A reason for reporting is required." };
    const users: (User & { pass: string })[] = safeJsonParse(safeGetItem('users'), []);
    const reportedUserIndex = users.findIndex(u => u.email === reportedProject.ownerEmail);
    const reportingUserIndex = users.findIndex(u => u.email === currentUser.email);
    if (reportedUserIndex === -1) return { success: false, message: "Reported user not found." };
    if (reportingUserIndex === -1) return { success: false, message: "Could not identify reporting user."};
    const isReportValid = !reason.toLowerCase().includes('test_invalid');
    if (isReportValid) {
        const reportedUser = users[reportedUserIndex];
        reportedUser.points = Math.max(0, (reportedUser.points || 0) - 50);
        reportedUser.warnings = (reportedUser.warnings || 0) + 1;
        if (reportedUser.warnings >= 2) reportedUser.isBanned = true;
        users[reportedUserIndex] = reportedUser;
        safeSetItem('users', JSON.stringify(users));
        return { success: true, message: "تم إرسال البلاغ. تم تحذير المستخدم المبلغ عنه." };
    } else {
        const reporter = users[reportingUserIndex];
        reporter.points = Math.max(0, (reporter.points || 0) - 50);
        reporter.warnings = (reporter.warnings || 0) + 1;
        if (reporter.warnings >= 2) reporter.isBanned = true;
        users[reportingUserIndex] = reporter;
        safeSetItem('users', JSON.stringify(users));
        await updateUser({ points: reporter.points, warnings: reporter.warnings, isBanned: reporter.isBanned });
        return { success: true, message: "تم اعتبار بلاغك غير صالح. تم تسجيل تحذير لك." };
    }
  };

  const applyReferralCode = async (code: string): Promise<{ success: boolean; message: string }> => {
    if (!currentUser) return { success: false, message: 'يجب تسجيل الدخول أولاً.' };
    if (currentUser.referralCodeUsed) return { success: false, message: 'لقد استخدمت رمز إحالة بالفعل.' };
    if (currentUser.referralCode === code) return { success: false, message: 'لا يمكنك استخدام رمز الإحالة الخاص بك.' };
    const users: (User & { pass: string })[] = safeJsonParse(safeGetItem('users'), []);
    const referrerIndex = users.findIndex(u => u.referralCode === code);
    if (referrerIndex === -1) return { success: false, message: 'رمز الإحالة غير صالح.' };
    const referrer = users[referrerIndex];
    const referrerPoints = (referrer.points || 0) + 200;
    users[referrerIndex] = { ...referrer, points: referrerPoints };
    const currentUserBonus = 50;
    await updateUser({ points: (currentUser.points || 0) + currentUserBonus, referralCodeUsed: true });
    safeSetItem('users', JSON.stringify(users));
    return { success: true, message: `تهانينا! لقد حصلت على ${currentUserBonus} نقطة. حصل صديقك على 200 نقطة.` };
  };

  return (
    <AuthContext.Provider value={{ currentUser, logout, updateUser, upgradePlan, redeemPointsForPlan, reportProject, applyReferralCode }}>
      {children}
    </AuthContext.Provider>
  );
};

import React, { useState, useEffect } from 'react';
