interface AuthProps {
  onBackToLanding?: () => void;
}

const Auth: React.FC<AuthProps> = ({ onBackToLanding }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [step, setStep] = useState<'details' | 'verify'>('details');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const { updateUser } = useAuth();

  // Form Fields
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');
  const [fullName, setFullName] = useState('');
  const [walletAddress, setWalletAddress] = useState('');
  const [selectedWalletType, setSelectedWalletType] = useState(CRYPTO_WALLETS[0].name);
  const [verificationCode, setVerificationCode] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');

  useEffect(() => {
      // Restore saved verification code if any
      const savedCode = localStorage.getItem('auth_verification_code');
      if (savedCode) {
          setGeneratedCode(savedCode);
      }
  }, []);

  const generateVerificationCode = () => {
      const code = Math.random().toString(36).substring(2, 8).toUpperCase();
      setGeneratedCode(code);
      localStorage.setItem('auth_verification_code', code);
      return code;
  };

  const executeAuthLogic = async () => {
        setIsLoading(true);
        // Simulate API call
        setTimeout(async () => {
            try {
                if (isLogin) {
                    // Mock login
                    const users = JSON.parse(localStorage.getItem('users') || '[]');
                    const user = users.find((u: any) => u.email === email && u.pass === password);
                    if (user) {
                        // Ensure new fields are present in old records or update them
                        const userToStore = {
                            ...user,
                            uniqueLoginCode: user.uniqueLoginCode || generatedCode
                        };
                        localStorage.setItem('currentUser', JSON.stringify(userToStore));
                        window.location.reload(); // Refresh to trigger AuthContext update
                    } else {
                        setError('بيانات الدخول غير صحيحة.');
                    }
                } else {
                    // Mock signup
                    const users = JSON.parse(localStorage.getItem('users') || '[]');
                    if (users.some((u: any) => u.email === email)) {
                        setError('البريد الإلكتروني مستخدم بالفعل.');
                    } else {
                        const newUser = {
                            email,
                            pass: password,
                            name: fullName,
                            username,
                            walletAddress,
                            plan: 'free',
                            points: 100,
                            isNewUser: true,
                            uniqueLoginCode: generatedCode,
                            profilePictureUrl: '' // Placeholder
                        };
                        users.push(newUser);
                        localStorage.setItem('users', JSON.stringify(users));
                        localStorage.setItem('currentUser', JSON.stringify(newUser));
                        window.location.reload();
                    }
                }
            } catch (err) {
                setError('حدث خطأ غير متوقع.');
            } finally {
                setIsLoading(false);
            }
        }, 1500);
  };

  const handleAuthAction = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (step === 'details') {
        if (!email || !password) {
            setError('البريد الإلكتروني وكلمة المرور مطلوبان.');
            return;
        }

        if (isLogin) {
            // Skip verification for login
            executeAuthLogic();
            return;
        }

        if (!username || !fullName || !walletAddress) {
            setError('جميع الحقول مطلوبة لإنشاء الحساب.');
            return;
        }
        // Proceed to verification
        if (!generatedCode) {
            generateVerificationCode();
        }
        setStep('verify');
    } else {
        // Verification Step
        if (verificationCode !== generatedCode) {
            setError('رمز التحقق غير صحيح.');
            return;
        }
        executeAuthLogic();
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-4xl mx-auto">
