                            <div>
                                <label className="block text-xs text-slate-400 mb-1">كلمة المرور</label>
                                <input 
                                    type="password" 
                                    value={password} 
                                    onChange={e => setPassword(e.target.value)} 
                                    className="w-full bg-slate-900 border border-slate-600 rounded-lg p-2.5 text-white focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                                    required
                                />
                            </div>

                            {error && <p className="text-red-400 text-sm text-center">{error}</p>}

                            <button type="submit" disabled={isLoading} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3 px-4 rounded-lg transition-colors flex justify-center items-center gap-2">
                                {isLoading ? <SpinnerIcon className="w-5 h-5 animate-spin"/> : (isLogin ? 'تسجيل الدخول' : 'إنشاء حساب')}
                            </button>

                            <p className="text-center text-sm text-slate-400 mt-4">
                                {isLogin ? 'ليس لديك حساب؟' : 'لديك حساب بالفعل؟'}{' '}
                                <button type="button" onClick={() => { setIsLogin(!isLogin); setError(''); setStep('details'); }} className="text-indigo-400 hover:text-indigo-300 font-semibold underline">
                                    {isLogin ? 'أنشئ حساباً' : 'سجل دخولك'}
                                </button>
                            </p>
                        </form>
                    )}
                </div>
            </div>
        </div>
      </div>
    </div>
  );
};

